#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[repr(u32)]
pub enum NodeTag {
    Null = 0,
    AggregateFunctionCall = 1,
    CastExpr = 2,
    ColumnRef = 3,
    CompoundSelect = 4,
    SubqueryExpr = 5,
    ExistsExpr = 6,
    InExpr = 7,
    IsExpr = 8,
    BetweenExpr = 9,
    LikeExpr = 10,
    CaseExpr = 11,
    CaseWhen = 12,
    CaseWhenList = 13,
    ForeignKeyClause = 14,
    ColumnConstraint = 15,
    ColumnConstraintList = 16,
    ColumnDef = 17,
    ColumnDefList = 18,
    TableConstraint = 19,
    TableConstraintList = 20,
    CreateTableStmt = 21,
    CteDefinition = 22,
    CteList = 23,
    WithClause = 24,
    DeleteStmt = 25,
    SetClause = 26,
    SetClauseList = 27,
    UpdateStmt = 28,
    InsertStmt = 29,
    BinaryExpr = 30,
    UnaryExpr = 31,
    Literal = 32,
    ExprList = 33,
    FunctionCall = 34,
    Variable = 35,
    CollateExpr = 36,
    RaiseExpr = 37,
    QualifiedName = 38,
    DropStmt = 39,
    AlterTableStmt = 40,
    TransactionStmt = 41,
    SavepointStmt = 42,
    ResultColumn = 43,
    ResultColumnList = 44,
    SelectStmt = 45,
    OrderingTerm = 46,
    OrderByList = 47,
    LimitClause = 48,
    TableRef = 49,
    SubqueryTableSource = 50,
    JoinClause = 51,
    JoinPrefix = 52,
    TriggerEvent = 53,
    TriggerCmdList = 54,
    CreateTriggerStmt = 55,
    CreateVirtualTableStmt = 56,
    PragmaStmt = 57,
    AnalyzeStmt = 58,
    AttachStmt = 59,
    DetachStmt = 60,
    VacuumStmt = 61,
    ExplainStmt = 62,
    CreateIndexStmt = 63,
    CreateViewStmt = 64,
    ValuesRowList = 65,
    ValuesClause = 66,
    FrameBound = 67,
    FrameSpec = 68,
    WindowDef = 69,
    WindowDefList = 70,
    NamedWindowDef = 71,
    NamedWindowDefList = 72,
    FilterOver = 73,
}

impl NodeTag {
    pub fn from_raw(raw: u32) -> Option<NodeTag> {
        match raw {
            0 => Some(NodeTag::Null),
            1 => Some(NodeTag::AggregateFunctionCall),
            2 => Some(NodeTag::CastExpr),
            3 => Some(NodeTag::ColumnRef),
            4 => Some(NodeTag::CompoundSelect),
            5 => Some(NodeTag::SubqueryExpr),
            6 => Some(NodeTag::ExistsExpr),
            7 => Some(NodeTag::InExpr),
            8 => Some(NodeTag::IsExpr),
            9 => Some(NodeTag::BetweenExpr),
            10 => Some(NodeTag::LikeExpr),
            11 => Some(NodeTag::CaseExpr),
            12 => Some(NodeTag::CaseWhen),
            13 => Some(NodeTag::CaseWhenList),
            14 => Some(NodeTag::ForeignKeyClause),
            15 => Some(NodeTag::ColumnConstraint),
            16 => Some(NodeTag::ColumnConstraintList),
            17 => Some(NodeTag::ColumnDef),
            18 => Some(NodeTag::ColumnDefList),
            19 => Some(NodeTag::TableConstraint),
            20 => Some(NodeTag::TableConstraintList),
            21 => Some(NodeTag::CreateTableStmt),
            22 => Some(NodeTag::CteDefinition),
            23 => Some(NodeTag::CteList),
            24 => Some(NodeTag::WithClause),
            25 => Some(NodeTag::DeleteStmt),
            26 => Some(NodeTag::SetClause),
            27 => Some(NodeTag::SetClauseList),
            28 => Some(NodeTag::UpdateStmt),
            29 => Some(NodeTag::InsertStmt),
            30 => Some(NodeTag::BinaryExpr),
            31 => Some(NodeTag::UnaryExpr),
            32 => Some(NodeTag::Literal),
            33 => Some(NodeTag::ExprList),
            34 => Some(NodeTag::FunctionCall),
            35 => Some(NodeTag::Variable),
            36 => Some(NodeTag::CollateExpr),
            37 => Some(NodeTag::RaiseExpr),
            38 => Some(NodeTag::QualifiedName),
            39 => Some(NodeTag::DropStmt),
            40 => Some(NodeTag::AlterTableStmt),
            41 => Some(NodeTag::TransactionStmt),
            42 => Some(NodeTag::SavepointStmt),
            43 => Some(NodeTag::ResultColumn),
            44 => Some(NodeTag::ResultColumnList),
            45 => Some(NodeTag::SelectStmt),
            46 => Some(NodeTag::OrderingTerm),
            47 => Some(NodeTag::OrderByList),
            48 => Some(NodeTag::LimitClause),
            49 => Some(NodeTag::TableRef),
            50 => Some(NodeTag::SubqueryTableSource),
            51 => Some(NodeTag::JoinClause),
            52 => Some(NodeTag::JoinPrefix),
            53 => Some(NodeTag::TriggerEvent),
            54 => Some(NodeTag::TriggerCmdList),
            55 => Some(NodeTag::CreateTriggerStmt),
            56 => Some(NodeTag::CreateVirtualTableStmt),
            57 => Some(NodeTag::PragmaStmt),
            58 => Some(NodeTag::AnalyzeStmt),
            59 => Some(NodeTag::AttachStmt),
            60 => Some(NodeTag::DetachStmt),
            61 => Some(NodeTag::VacuumStmt),
            62 => Some(NodeTag::ExplainStmt),
            63 => Some(NodeTag::CreateIndexStmt),
            64 => Some(NodeTag::CreateViewStmt),
            65 => Some(NodeTag::ValuesRowList),
            66 => Some(NodeTag::ValuesClause),
            67 => Some(NodeTag::FrameBound),
            68 => Some(NodeTag::FrameSpec),
            69 => Some(NodeTag::WindowDef),
            70 => Some(NodeTag::WindowDefList),
            71 => Some(NodeTag::NamedWindowDef),
            72 => Some(NodeTag::NamedWindowDefList),
            73 => Some(NodeTag::FilterOver),
            _ => None,
        }
    }

    pub fn is_list(&self) -> bool {
        matches!(self, NodeTag::CaseWhenList | NodeTag::ColumnConstraintList | NodeTag::ColumnDefList | NodeTag::TableConstraintList | NodeTag::CteList | NodeTag::SetClauseList | NodeTag::ExprList | NodeTag::ResultColumnList | NodeTag::OrderByList | NodeTag::TriggerCmdList | NodeTag::ValuesRowList | NodeTag::WindowDefList | NodeTag::NamedWindowDefList
        )
    }
}

