/// A typed AST node. Pattern-match to access the concrete type.
#[derive(Debug, Clone, Copy)]
pub enum Node<'a> {
    AggregateFunctionCall(&'a AggregateFunctionCall),
    CastExpr(&'a CastExpr),
    ColumnRef(&'a ColumnRef),
    CompoundSelect(&'a CompoundSelect),
    SubqueryExpr(&'a SubqueryExpr),
    ExistsExpr(&'a ExistsExpr),
    InExpr(&'a InExpr),
    IsExpr(&'a IsExpr),
    BetweenExpr(&'a BetweenExpr),
    LikeExpr(&'a LikeExpr),
    CaseExpr(&'a CaseExpr),
    CaseWhen(&'a CaseWhen),
    /// List of CaseWhen
    CaseWhenList(&'a NodeList),
    ForeignKeyClause(&'a ForeignKeyClause),
    ColumnConstraint(&'a ColumnConstraint),
    /// List of ColumnConstraint
    ColumnConstraintList(&'a NodeList),
    ColumnDef(&'a ColumnDef),
    /// List of ColumnDef
    ColumnDefList(&'a NodeList),
    TableConstraint(&'a TableConstraint),
    /// List of TableConstraint
    TableConstraintList(&'a NodeList),
    CreateTableStmt(&'a CreateTableStmt),
    CteDefinition(&'a CteDefinition),
    /// List of CteDefinition
    CteList(&'a NodeList),
    WithClause(&'a WithClause),
    DeleteStmt(&'a DeleteStmt),
    SetClause(&'a SetClause),
    /// List of SetClause
    SetClauseList(&'a NodeList),
    UpdateStmt(&'a UpdateStmt),
    InsertStmt(&'a InsertStmt),
    BinaryExpr(&'a BinaryExpr),
    UnaryExpr(&'a UnaryExpr),
    Literal(&'a Literal),
    /// List of Expr
    ExprList(&'a NodeList),
    FunctionCall(&'a FunctionCall),
    Variable(&'a Variable),
    CollateExpr(&'a CollateExpr),
    RaiseExpr(&'a RaiseExpr),
    QualifiedName(&'a QualifiedName),
    DropStmt(&'a DropStmt),
    AlterTableStmt(&'a AlterTableStmt),
    TransactionStmt(&'a TransactionStmt),
    SavepointStmt(&'a SavepointStmt),
    ResultColumn(&'a ResultColumn),
    /// List of ResultColumn
    ResultColumnList(&'a NodeList),
    SelectStmt(&'a SelectStmt),
    OrderingTerm(&'a OrderingTerm),
    /// List of OrderingTerm
    OrderByList(&'a NodeList),
    LimitClause(&'a LimitClause),
    TableRef(&'a TableRef),
    SubqueryTableSource(&'a SubqueryTableSource),
    JoinClause(&'a JoinClause),
    JoinPrefix(&'a JoinPrefix),
    TriggerEvent(&'a TriggerEvent),
    /// List of Stmt
    TriggerCmdList(&'a NodeList),
    CreateTriggerStmt(&'a CreateTriggerStmt),
    CreateVirtualTableStmt(&'a CreateVirtualTableStmt),
    PragmaStmt(&'a PragmaStmt),
    AnalyzeStmt(&'a AnalyzeStmt),
    AttachStmt(&'a AttachStmt),
    DetachStmt(&'a DetachStmt),
    VacuumStmt(&'a VacuumStmt),
    ExplainStmt(&'a ExplainStmt),
    CreateIndexStmt(&'a CreateIndexStmt),
    CreateViewStmt(&'a CreateViewStmt),
    /// List of ExprList
    ValuesRowList(&'a NodeList),
    ValuesClause(&'a ValuesClause),
    FrameBound(&'a FrameBound),
    FrameSpec(&'a FrameSpec),
    WindowDef(&'a WindowDef),
    /// List of WindowDef
    WindowDefList(&'a NodeList),
    NamedWindowDef(&'a NamedWindowDef),
    /// List of NamedWindowDef
    NamedWindowDefList(&'a NodeList),
    FilterOver(&'a FilterOver),
    /// Placeholder for PhantomData lifetime — never constructed.
    #[doc(hidden)]
    __Phantom(PhantomData<&'a ()>),
}

impl<'a> Node<'a> {
    /// Construct a typed `Node` from a raw arena pointer.
    ///
    /// # Safety
    /// `ptr` must be non-null, well-aligned, and valid for `'a`.
    /// Its first `u32` must be a valid `NodeTag` discriminant.
    pub(crate) unsafe fn from_raw(ptr: *const u32) -> Node<'a> {
        // SAFETY: caller guarantees ptr is valid for 'a with a valid tag.
        unsafe {
        let tag = NodeTag::from_raw(*ptr).unwrap_or(NodeTag::Null);
        match tag {
            NodeTag::AggregateFunctionCall => Node::AggregateFunctionCall(&*(ptr as *const AggregateFunctionCall)),
            NodeTag::CastExpr => Node::CastExpr(&*(ptr as *const CastExpr)),
            NodeTag::ColumnRef => Node::ColumnRef(&*(ptr as *const ColumnRef)),
            NodeTag::CompoundSelect => Node::CompoundSelect(&*(ptr as *const CompoundSelect)),
            NodeTag::SubqueryExpr => Node::SubqueryExpr(&*(ptr as *const SubqueryExpr)),
            NodeTag::ExistsExpr => Node::ExistsExpr(&*(ptr as *const ExistsExpr)),
            NodeTag::InExpr => Node::InExpr(&*(ptr as *const InExpr)),
            NodeTag::IsExpr => Node::IsExpr(&*(ptr as *const IsExpr)),
            NodeTag::BetweenExpr => Node::BetweenExpr(&*(ptr as *const BetweenExpr)),
            NodeTag::LikeExpr => Node::LikeExpr(&*(ptr as *const LikeExpr)),
            NodeTag::CaseExpr => Node::CaseExpr(&*(ptr as *const CaseExpr)),
            NodeTag::CaseWhen => Node::CaseWhen(&*(ptr as *const CaseWhen)),
            NodeTag::CaseWhenList => Node::CaseWhenList(&*(ptr as *const NodeList)),
            NodeTag::ForeignKeyClause => Node::ForeignKeyClause(&*(ptr as *const ForeignKeyClause)),
            NodeTag::ColumnConstraint => Node::ColumnConstraint(&*(ptr as *const ColumnConstraint)),
            NodeTag::ColumnConstraintList => Node::ColumnConstraintList(&*(ptr as *const NodeList)),
            NodeTag::ColumnDef => Node::ColumnDef(&*(ptr as *const ColumnDef)),
            NodeTag::ColumnDefList => Node::ColumnDefList(&*(ptr as *const NodeList)),
            NodeTag::TableConstraint => Node::TableConstraint(&*(ptr as *const TableConstraint)),
            NodeTag::TableConstraintList => Node::TableConstraintList(&*(ptr as *const NodeList)),
            NodeTag::CreateTableStmt => Node::CreateTableStmt(&*(ptr as *const CreateTableStmt)),
            NodeTag::CteDefinition => Node::CteDefinition(&*(ptr as *const CteDefinition)),
            NodeTag::CteList => Node::CteList(&*(ptr as *const NodeList)),
            NodeTag::WithClause => Node::WithClause(&*(ptr as *const WithClause)),
            NodeTag::DeleteStmt => Node::DeleteStmt(&*(ptr as *const DeleteStmt)),
            NodeTag::SetClause => Node::SetClause(&*(ptr as *const SetClause)),
            NodeTag::SetClauseList => Node::SetClauseList(&*(ptr as *const NodeList)),
            NodeTag::UpdateStmt => Node::UpdateStmt(&*(ptr as *const UpdateStmt)),
            NodeTag::InsertStmt => Node::InsertStmt(&*(ptr as *const InsertStmt)),
            NodeTag::BinaryExpr => Node::BinaryExpr(&*(ptr as *const BinaryExpr)),
            NodeTag::UnaryExpr => Node::UnaryExpr(&*(ptr as *const UnaryExpr)),
            NodeTag::Literal => Node::Literal(&*(ptr as *const Literal)),
            NodeTag::ExprList => Node::ExprList(&*(ptr as *const NodeList)),
            NodeTag::FunctionCall => Node::FunctionCall(&*(ptr as *const FunctionCall)),
            NodeTag::Variable => Node::Variable(&*(ptr as *const Variable)),
            NodeTag::CollateExpr => Node::CollateExpr(&*(ptr as *const CollateExpr)),
            NodeTag::RaiseExpr => Node::RaiseExpr(&*(ptr as *const RaiseExpr)),
            NodeTag::QualifiedName => Node::QualifiedName(&*(ptr as *const QualifiedName)),
            NodeTag::DropStmt => Node::DropStmt(&*(ptr as *const DropStmt)),
            NodeTag::AlterTableStmt => Node::AlterTableStmt(&*(ptr as *const AlterTableStmt)),
            NodeTag::TransactionStmt => Node::TransactionStmt(&*(ptr as *const TransactionStmt)),
            NodeTag::SavepointStmt => Node::SavepointStmt(&*(ptr as *const SavepointStmt)),
            NodeTag::ResultColumn => Node::ResultColumn(&*(ptr as *const ResultColumn)),
            NodeTag::ResultColumnList => Node::ResultColumnList(&*(ptr as *const NodeList)),
            NodeTag::SelectStmt => Node::SelectStmt(&*(ptr as *const SelectStmt)),
            NodeTag::OrderingTerm => Node::OrderingTerm(&*(ptr as *const OrderingTerm)),
            NodeTag::OrderByList => Node::OrderByList(&*(ptr as *const NodeList)),
            NodeTag::LimitClause => Node::LimitClause(&*(ptr as *const LimitClause)),
            NodeTag::TableRef => Node::TableRef(&*(ptr as *const TableRef)),
            NodeTag::SubqueryTableSource => Node::SubqueryTableSource(&*(ptr as *const SubqueryTableSource)),
            NodeTag::JoinClause => Node::JoinClause(&*(ptr as *const JoinClause)),
            NodeTag::JoinPrefix => Node::JoinPrefix(&*(ptr as *const JoinPrefix)),
            NodeTag::TriggerEvent => Node::TriggerEvent(&*(ptr as *const TriggerEvent)),
            NodeTag::TriggerCmdList => Node::TriggerCmdList(&*(ptr as *const NodeList)),
            NodeTag::CreateTriggerStmt => Node::CreateTriggerStmt(&*(ptr as *const CreateTriggerStmt)),
            NodeTag::CreateVirtualTableStmt => Node::CreateVirtualTableStmt(&*(ptr as *const CreateVirtualTableStmt)),
            NodeTag::PragmaStmt => Node::PragmaStmt(&*(ptr as *const PragmaStmt)),
            NodeTag::AnalyzeStmt => Node::AnalyzeStmt(&*(ptr as *const AnalyzeStmt)),
            NodeTag::AttachStmt => Node::AttachStmt(&*(ptr as *const AttachStmt)),
            NodeTag::DetachStmt => Node::DetachStmt(&*(ptr as *const DetachStmt)),
            NodeTag::VacuumStmt => Node::VacuumStmt(&*(ptr as *const VacuumStmt)),
            NodeTag::ExplainStmt => Node::ExplainStmt(&*(ptr as *const ExplainStmt)),
            NodeTag::CreateIndexStmt => Node::CreateIndexStmt(&*(ptr as *const CreateIndexStmt)),
            NodeTag::CreateViewStmt => Node::CreateViewStmt(&*(ptr as *const CreateViewStmt)),
            NodeTag::ValuesRowList => Node::ValuesRowList(&*(ptr as *const NodeList)),
            NodeTag::ValuesClause => Node::ValuesClause(&*(ptr as *const ValuesClause)),
            NodeTag::FrameBound => Node::FrameBound(&*(ptr as *const FrameBound)),
            NodeTag::FrameSpec => Node::FrameSpec(&*(ptr as *const FrameSpec)),
            NodeTag::WindowDef => Node::WindowDef(&*(ptr as *const WindowDef)),
            NodeTag::WindowDefList => Node::WindowDefList(&*(ptr as *const NodeList)),
            NodeTag::NamedWindowDef => Node::NamedWindowDef(&*(ptr as *const NamedWindowDef)),
            NodeTag::NamedWindowDefList => Node::NamedWindowDefList(&*(ptr as *const NodeList)),
            NodeTag::FilterOver => Node::FilterOver(&*(ptr as *const FilterOver)),
            _ => unreachable!("unknown node tag"),
        }
        } // unsafe
    }

    /// The node's tag.
    pub fn tag(&self) -> NodeTag {
        match self {
            Node::AggregateFunctionCall(_) => NodeTag::AggregateFunctionCall,
            Node::CastExpr(_) => NodeTag::CastExpr,
            Node::ColumnRef(_) => NodeTag::ColumnRef,
            Node::CompoundSelect(_) => NodeTag::CompoundSelect,
            Node::SubqueryExpr(_) => NodeTag::SubqueryExpr,
            Node::ExistsExpr(_) => NodeTag::ExistsExpr,
            Node::InExpr(_) => NodeTag::InExpr,
            Node::IsExpr(_) => NodeTag::IsExpr,
            Node::BetweenExpr(_) => NodeTag::BetweenExpr,
            Node::LikeExpr(_) => NodeTag::LikeExpr,
            Node::CaseExpr(_) => NodeTag::CaseExpr,
            Node::CaseWhen(_) => NodeTag::CaseWhen,
            Node::CaseWhenList(_) => NodeTag::CaseWhenList,
            Node::ForeignKeyClause(_) => NodeTag::ForeignKeyClause,
            Node::ColumnConstraint(_) => NodeTag::ColumnConstraint,
            Node::ColumnConstraintList(_) => NodeTag::ColumnConstraintList,
            Node::ColumnDef(_) => NodeTag::ColumnDef,
            Node::ColumnDefList(_) => NodeTag::ColumnDefList,
            Node::TableConstraint(_) => NodeTag::TableConstraint,
            Node::TableConstraintList(_) => NodeTag::TableConstraintList,
            Node::CreateTableStmt(_) => NodeTag::CreateTableStmt,
            Node::CteDefinition(_) => NodeTag::CteDefinition,
            Node::CteList(_) => NodeTag::CteList,
            Node::WithClause(_) => NodeTag::WithClause,
            Node::DeleteStmt(_) => NodeTag::DeleteStmt,
            Node::SetClause(_) => NodeTag::SetClause,
            Node::SetClauseList(_) => NodeTag::SetClauseList,
            Node::UpdateStmt(_) => NodeTag::UpdateStmt,
            Node::InsertStmt(_) => NodeTag::InsertStmt,
            Node::BinaryExpr(_) => NodeTag::BinaryExpr,
            Node::UnaryExpr(_) => NodeTag::UnaryExpr,
            Node::Literal(_) => NodeTag::Literal,
            Node::ExprList(_) => NodeTag::ExprList,
            Node::FunctionCall(_) => NodeTag::FunctionCall,
            Node::Variable(_) => NodeTag::Variable,
            Node::CollateExpr(_) => NodeTag::CollateExpr,
            Node::RaiseExpr(_) => NodeTag::RaiseExpr,
            Node::QualifiedName(_) => NodeTag::QualifiedName,
            Node::DropStmt(_) => NodeTag::DropStmt,
            Node::AlterTableStmt(_) => NodeTag::AlterTableStmt,
            Node::TransactionStmt(_) => NodeTag::TransactionStmt,
            Node::SavepointStmt(_) => NodeTag::SavepointStmt,
            Node::ResultColumn(_) => NodeTag::ResultColumn,
            Node::ResultColumnList(_) => NodeTag::ResultColumnList,
            Node::SelectStmt(_) => NodeTag::SelectStmt,
            Node::OrderingTerm(_) => NodeTag::OrderingTerm,
            Node::OrderByList(_) => NodeTag::OrderByList,
            Node::LimitClause(_) => NodeTag::LimitClause,
            Node::TableRef(_) => NodeTag::TableRef,
            Node::SubqueryTableSource(_) => NodeTag::SubqueryTableSource,
            Node::JoinClause(_) => NodeTag::JoinClause,
            Node::JoinPrefix(_) => NodeTag::JoinPrefix,
            Node::TriggerEvent(_) => NodeTag::TriggerEvent,
            Node::TriggerCmdList(_) => NodeTag::TriggerCmdList,
            Node::CreateTriggerStmt(_) => NodeTag::CreateTriggerStmt,
            Node::CreateVirtualTableStmt(_) => NodeTag::CreateVirtualTableStmt,
            Node::PragmaStmt(_) => NodeTag::PragmaStmt,
            Node::AnalyzeStmt(_) => NodeTag::AnalyzeStmt,
            Node::AttachStmt(_) => NodeTag::AttachStmt,
            Node::DetachStmt(_) => NodeTag::DetachStmt,
            Node::VacuumStmt(_) => NodeTag::VacuumStmt,
            Node::ExplainStmt(_) => NodeTag::ExplainStmt,
            Node::CreateIndexStmt(_) => NodeTag::CreateIndexStmt,
            Node::CreateViewStmt(_) => NodeTag::CreateViewStmt,
            Node::ValuesRowList(_) => NodeTag::ValuesRowList,
            Node::ValuesClause(_) => NodeTag::ValuesClause,
            Node::FrameBound(_) => NodeTag::FrameBound,
            Node::FrameSpec(_) => NodeTag::FrameSpec,
            Node::WindowDef(_) => NodeTag::WindowDef,
            Node::WindowDefList(_) => NodeTag::WindowDefList,
            Node::NamedWindowDef(_) => NodeTag::NamedWindowDef,
            Node::NamedWindowDefList(_) => NodeTag::NamedWindowDefList,
            Node::FilterOver(_) => NodeTag::FilterOver,
            Node::__Phantom(_) => unreachable!(),
        }
    }

    /// If this is a list node, return the list.
    pub fn as_list(&self) -> Option<&'a NodeList> {
        match self {
            Node::CaseWhenList(l) => Some(l),
            Node::ColumnConstraintList(l) => Some(l),
            Node::ColumnDefList(l) => Some(l),
            Node::TableConstraintList(l) => Some(l),
            Node::CteList(l) => Some(l),
            Node::SetClauseList(l) => Some(l),
            Node::ExprList(l) => Some(l),
            Node::ResultColumnList(l) => Some(l),
            Node::OrderByList(l) => Some(l),
            Node::TriggerCmdList(l) => Some(l),
            Node::ValuesRowList(l) => Some(l),
            Node::WindowDefList(l) => Some(l),
            Node::NamedWindowDefList(l) => Some(l),
            _ => None,
        }
    }
}

